package main


import (
  "fmt"
  "net/http"
  "io"
)


func main() {


  url := "https://192.168.0.1/proxy/protect/integration/v1/subscribe/devices"
  method := "GET"


  client := &http.Client {
  }
  req, err := http.NewRequest(method, url, nil)


  if err != nil {
    fmt.Println(err)
    return
  }
  req.Header.Add("Accept", "application/json")
  req.Header.Add("X-API-Key", "<X-API-Key>")


  res, err := client.Do(req)
  if err != nil {
    fmt.Println(err)
    return
  }
  defer res.Body.Close()


  body, err := io.ReadAll(res.Body)
  if err != nil {
    fmt.Println(err)
    return
  }
  fmt.Println(string(body))
}

